#include <vector>
#include <string>
#include <unordered_map>
#include <algorithm>

using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    unordered_map<string, int> orderMap = {
        {"electronics", 0},
        {"grocery", 1},
        {"pharmacy", 2},
        {"restaurant", 3}
    };

    vector<pair<int, string>> temp;
    int n = code.size();

    for (int i = 0; i < n; i++) {
        if (!isActive[i]) 
            continue;

        if (orderMap.find(businessLine[i]) == orderMap.end()) 
