                (c >= '0' && c <= '9') || 
                c == '_') {
                continue;
            }
            validCode = false;
            break;
        }

        if (!validCode) 
            continue;

        int order = orderMap[businessLine[i]];
        temp.push_back(make_pair(order, code[i]));
    }

    sort(temp.begin(), temp.end(), [](const pair<int, string>& a, const pair<int, string>& b) {
        if (a.first != b.first) 
